import{_ as a,o as t,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Meta Advanced Mobile Measurement","description":"","frontmatter":{"title":"Meta Advanced Mobile Measurement","slug":"meta-advanced-mobile-measurement"},"headers":[],"relativePath":"marketer-hub/meta-advanced-mobile-measurement.md","filePath":"marketer-hub/meta-advanced-mobile-measurement.md"}'),n={name:"marketer-hub/meta-advanced-mobile-measurement.md"};function s(i,e,l,m,d,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Meta is re-enabling Advanced Mobile Measurement (AMM) reporting. Starting June 17, 2025 we will be able to share attributed last touch information in non-aggregated form with advertisers who have signed Meta’s AMM terms. This update will enable app advertisers to measure ad performance more precisely within their own analytics and business intelligence tools, with inclusion of attributed Meta ads data in MMPs’ row level reporting.</p><p>If you are interested in signing Meta’s Advanced Mobile Measurement Terms, you can do so via <a href="https://developers.facebook.com/advanced_mobile_measurement/terms" target="_blank" rel="noreferrer">this link</a>.</p><h2 id="key-takeaways" tabindex="-1">Key takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key takeaways&quot;">​</a></h2><ul><li><p><strong>What’s changing</strong>: As part of Facebook’s Mobile Measurement Partner program, we receive last touch information that is associated with a conversion. After AMM was discontinued in 2021, we were able to share this last touch information with shared clients (advertisers) only in aggregated form. Starting on June 17, 2025 advertisers are able to sign AMM terms with Meta that will enable us to pass this last-touch information back to you in non-aggregated form, as long as you have signed the terms with Meta.</p><ul><li>You can sign the terms at <a href="https://developers.facebook.com/advanced_mobile_measurement/terms" target="_blank" rel="noreferrer">this link</a>.</li></ul></li><li><p>This change does not impact the data we receive from Meta as part of our partnership. Therefore, we do not expect app campaign performance to change. The only change is that if you sign the AMM terms, you will now have access to non-aggregated conversion data for measurement.</p></li><li><p>In order to access/accept the Advanced Mobile Measurement Terms, <strong>Administrator role for an App</strong> is required.</p></li><li><p>For more information on app roles, see <a href="https://developers.facebook.com/docs/development/build-and-test/app-roles/" target="_blank" rel="noreferrer">this dev doc</a>.</p></li><li><p>Only App Administrators are able to modify app roles. For more information on how to manage roles for an app, see <a href="https://www.facebook.com/business/help/business/help/299504287548592" target="_blank" rel="noreferrer">this Help article</a>.</p></li></ul>',5)])])}const u=a(n,[["render",s]]);export{p as __pageData,u as default};
